"use client"

import { useState, useCallback } from "react"
import Link from "next/link"
import { Plus, FileText, Send, Edit3, Eye } from "lucide-react"
import { PageHeader } from "@/components/page-header"
import {
  getInformes,
  getContrato,
  getConfiguracion,
  addInforme,
} from "@/lib/store"
import { format, parseISO } from "date-fns"
import { es } from "date-fns/locale"
import { toast } from "sonner"
import type { EstadoInforme } from "@/lib/types"

const estadoBadge: Record<
  EstadoInforme,
  { label: string; className: string }
> = {
  borrador: {
    label: "Borrador",
    className: "bg-muted text-muted-foreground",
  },
  finalizado: {
    label: "Finalizado",
    className: "bg-chart-2/15 text-chart-2",
  },
  enviado: {
    label: "Enviado",
    className: "bg-chart-1/15 text-chart-1",
  },
}

const estadoIcon: Record<EstadoInforme, typeof FileText> = {
  borrador: Edit3,
  finalizado: FileText,
  enviado: Send,
}

export default function InformesPage() {
  const [version, setVersion] = useState(0)
  const refresh = useCallback(() => setVersion((v) => v + 1), [])

  void version
  const informes = getInformes()
  const contrato = getContrato()
  const configuracion = getConfiguracion()

  function handleGenerate() {
    addInforme({
      contratoId: contrato.id,
      periodo: format(
        parseISO(configuracion.periodoActualInicio),
        "MMMM yyyy",
        { locale: es }
      ),
      fechaInicio: configuracion.periodoActualInicio,
      fechaFin: configuracion.periodoActualFin,
      estado: "borrador",
      plantilla: configuracion.plantillaSeleccionada,
    })
    toast.success("Informe generado como borrador")
    refresh()
  }

  const sorted = [...informes].sort(
    (a, b) =>
      new Date(b.fechaGeneracion).getTime() -
      new Date(a.fechaGeneracion).getTime()
  )

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        titulo="Informes de Gestion"
        descripcion="Genera y gestiona los informes periodicos de actividades contractuales"
      >
        <button
          onClick={handleGenerate}
          className="flex items-center gap-2 rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
        >
          <Plus className="h-4 w-4" />
          Generar Informe
        </button>
      </PageHeader>

      {sorted.length === 0 ? (
        <div className="flex flex-col items-center gap-3 py-16">
          <div className="flex h-14 w-14 items-center justify-center rounded-full bg-muted">
            <FileText className="h-7 w-7 text-muted-foreground" />
          </div>
          <p className="text-sm font-medium text-foreground">
            No hay informes generados
          </p>
          <p className="text-xs text-muted-foreground">
            Genera tu primer informe para el periodo actual
          </p>
        </div>
      ) : (
        <div className="flex flex-col gap-3">
          {sorted.map((informe) => {
            const badge = estadoBadge[informe.estado]
            const StatusIcon = estadoIcon[informe.estado]
            return (
              <Link
                key={informe.id}
                href={`/informes/${informe.id}`}
                className="group flex items-center gap-4 rounded-lg border border-border bg-card p-4 transition-colors hover:border-primary/30 hover:bg-accent/30"
              >
                <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-md bg-primary/10">
                  <StatusIcon className="h-5 w-5 text-primary" />
                </div>
                <div className="flex min-w-0 flex-1 flex-col gap-0.5">
                  <div className="flex items-center gap-2">
                    <h3 className="text-sm font-semibold text-card-foreground">
                      Informe - {informe.periodo}
                    </h3>
                    <span
                      className={`rounded-full px-2.5 py-0.5 text-xs font-medium ${badge.className}`}
                    >
                      {badge.label}
                    </span>
                  </div>
                  <p className="text-xs text-muted-foreground">
                    Periodo:{" "}
                    {format(parseISO(informe.fechaInicio), "d MMM", {
                      locale: es,
                    })}{" "}
                    -{" "}
                    {format(parseISO(informe.fechaFin), "d MMM yyyy", {
                      locale: es,
                    })}{" "}
                    | Generado:{" "}
                    {format(
                      parseISO(informe.fechaGeneracion),
                      "d MMM yyyy",
                      { locale: es }
                    )}
                  </p>
                </div>
                <Eye className="h-4 w-4 shrink-0 text-muted-foreground opacity-0 transition-opacity group-hover:opacity-100" />
              </Link>
            )
          })}
        </div>
      )}
    </div>
  )
}
